import{_ as i,o,c as a,a2 as s}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-051 — Outbound learn-link stewardship","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-051.md","filePath":"adr/ADR-051.md"}'),t={name:"adr/ADR-051.md"};function n(l,e,r,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="adr-051-—-outbound-learn-link-stewardship" tabindex="-1">ADR-051 — Outbound learn-link stewardship <a class="header-anchor" href="#adr-051-—-outbound-learn-link-stewardship" aria-label="Permalink to &quot;ADR-051 — Outbound learn-link stewardship&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Extends · <code>docs/adr/ADR-046.md</code> (agency-first imagery sourcing) and <code>docs/adr/ADR-047.md</code> (provenance manifests + license stewardship) Closes into · RFC-015 (LEARN-link rollout) Scope · <code>static/data/link-provenance.json</code>, <code>static/data/source-logos.json</code>, <code>static/data/schemas/link-provenance.schema.json</code>, <code>scripts/build-link-provenance.ts</code>, <code>scripts/validate-data.ts</code>, <code>scripts/check-learn-links.ts</code>, <code>src/lib/components/LinkCredit.svelte</code>, <code>src/lib/data.ts</code>, <code>src/lib/library-grouping.ts</code>, <code>src/routes/library/+page.svelte</code>, <code>src/routes/+layout.svelte</code></p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-046 locked the source priority for build-time <strong>imagery</strong> and ADR-047 layered <strong>provenance manifests + a fail-closed pipeline</strong> on top. Together they cover every shipped image and every paraphrased editorial fragment.</p><p>LEARN-tab outbound links — the single largest editorial surface in the app (<a href="./../research/learn-link-audit"><code>docs/research/learn-link-audit.md</code></a> inventories 925 of them) — were left out of that contract. The audit shows the same drift pattern that the imagery contract corrected:</p><ul><li>76 % of outbound links go to NASA-domain hosts and Wikipedia.</li><li>Only 4 % go to non-US agency sites; zero go to native-language Roscosmos / CNSA / JAXA-jp / ISRO-hi pages despite the obvious primary sources.</li><li>Several non-US missions (Chang&#39;e 5, Chang&#39;e 6, Chandrayaan-3, Tianwen-1) link to nothing but Wikipedia.</li><li>Six of seven ISS Russian-segment modules miss <code>roscosmos.ru</code> entirely.</li><li>No per-link provenance, no <code>hreflang</code>, no <code>rel=&quot;external&quot;</code>, no link-checker, no public bill-of-links.</li></ul><p>A user lands on a non-US mission detail panel today and the LEARN tab points them at Wikipedia, when the operating agency&#39;s own page exists. That is editorial laziness in a project that re-distributes other people&#39;s work — and it is disrespectful to the agencies that made the missions happen.</p><p>ADR-051 brings outbound-link discipline to parity with ADR-046 / ADR-047.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Adopt <strong>per-link provenance with a fail-closed pipeline</strong> and a publishing contract that routes users to operator pages first, in their native language when possible, with a public bill-of-links page.</p><h3 id="manifest" tabindex="-1">Manifest <a class="header-anchor" href="#manifest" aria-label="Permalink to &quot;Manifest&quot;">​</a></h3><p><code>static/data/link-provenance.json</code> — one entry per <code>(entity_id, url)</code> pair. Required fields:</p><ul><li><code>id</code> — stable id <code>entity_id__hash(url)</code></li><li><code>entity_id</code> — id of the mission / module / planet / etc. that the link belongs to</li><li><code>route</code> — app route where the link is shown (<code>/missions</code>, <code>/iss</code>, <code>/moon</code>, <code>/mars</code>, <code>/explore</code>, <code>/earth</code>)</li><li><code>category</code> — data-file source (<code>mission</code>, <code>iss-module</code>, <code>iss-visitor</code>, <code>earth-object</code>, <code>moon-site</code>, <code>mars-site</code>, <code>planet</code>, <code>sun</code>, <code>rocket</code>, <code>small-body</code>)</li><li><code>url</code> — canonicalised target (no <code>?utm_*</code>, <code>?fbclid</code>, no AMP suffix, no <code>m.</code> mobile prefix)</li><li><code>label</code> — display label (English; locale overlays may translate it)</li><li><code>tier</code> — <code>intro</code> | <code>core</code> | <code>deep</code></li><li><code>source_id</code> — must resolve in <code>static/data/source-logos.json</code></li><li><code>language</code> — BCP-47 code (<code>en</code>, <code>ru</code>, <code>zh</code>, <code>ja</code>, <code>hi</code>, <code>es</code>, …); <code>*</code> for multi-lingual landing pages</li><li><code>kind</code> — <code>agency-official</code> | <code>mission-microsite</code> | <code>science-publisher</code> | <code>encyclopedic</code> | <code>educational</code> | <code>community</code> | <code>vendor-official</code></li><li><code>fair_use_rationale</code> — short string; &quot;external reference; rel=noopener noreferrer external&quot; is the default</li><li><code>last_verified</code> — ISO date; updated by the link-checker</li></ul><p>Optional fields:</p><ul><li><code>replaced_with</code> — when a link is removed because of a 404 or because a better source surfaced; records the new URL so the change is not silent</li><li><code>notes</code> — author notes (e.g. &quot;press kit redirects to a partial paywall after 30 s; deep tier appropriate&quot;)</li></ul><p>Schema: <code>static/data/schemas/link-provenance.schema.json</code>.</p><h3 id="source-diversity-targets" tabindex="-1">Source diversity targets <a class="header-anchor" href="#source-diversity-targets" aria-label="Permalink to &quot;Source diversity targets&quot;">​</a></h3><ul><li>Every non-US entity has at least one <code>agency-official</code> <code>intro</code> link to its operating agency. The first <code>intro</code> link on a non-US entity <em>must</em> be the agency portal.</li><li>No entity has Wikipedia as its sole source.</li><li>The non-US share of the inventory rises from ~4 % to ≥ 15 % across the corpus.</li><li>100 % first-link agency coverage on non-US entities.</li></ul><h3 id="locale-fallback-chain" tabindex="-1">Locale fallback chain <a class="header-anchor" href="#locale-fallback-chain" aria-label="Permalink to &quot;Locale fallback chain&quot;">​</a></h3><p>When the UI is rendering a LEARN link list, the data layer picks links in this order, breaking ties by <code>last_verified</code> desc:</p><ol><li>Links whose <code>language</code> matches the active UI locale.</li><li>Links whose <code>language</code> matches the operator&#39;s native language (Roscosmos → <code>ru</code>, CNSA → <code>zh</code>, JAXA → <code>ja</code>, ISRO → <code>hi</code> or <code>en</code>, MBRSC → <code>ar</code>).</li><li>English (<code>en</code>).</li><li>Multi-lingual landing pages (<code>*</code>).</li></ol><p>The fallback chain is <em>additive</em> — a UI locale never <em>hides</em> a non-matching link, it only re-orders. Native-language agency pages stay visible to every user.</p><h3 id="rendering-rules" tabindex="-1">Rendering rules <a class="header-anchor" href="#rendering-rules" aria-label="Permalink to &quot;Rendering rules&quot;">​</a></h3><p>Every outbound LEARN link renders as:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">{link.url}</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_blank&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;noopener noreferrer external&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  hreflang</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">{link.language}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {link.label} ↗</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">LinkCredit</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> link</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">{link}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><p><code>&lt;LinkCredit /&gt;</code> renders below the anchor: <code>Source name · language · last verified</code>. Rendered in every panel that shows LEARN links: <code>MissionPanel</code>, <code>IssModulePanel</code>, <code>PlanetPanel</code>, <code>SunPanel</code>, <code>SmallBodyPanel</code>, plus the route components for <code>/moon</code>, <code>/mars</code>, <code>/earth</code> that render their own LEARN sections.</p><h3 id="public-disclosure" tabindex="-1">Public disclosure <a class="header-anchor" href="#public-disclosure" aria-label="Permalink to &quot;Public disclosure&quot;">​</a></h3><p>A new route <code>/library</code> lists every outbound link in the manifest, grouped by source, sorted <strong>newest verified first</strong> within each source. Same architecture as <code>/credits</code> (ADR-047): top intro, table of contents, per-source section with logo + license summary + entry list.</p><p>The public footer (<code>src/routes/+layout.svelte</code>) gains a second link so <code>/credits</code> and <code>/library</code> sit together in the bottom-trailing strip.</p><p>The Mission Library label on <code>/missions</code> is renamed to <strong>Mission Catalog</strong> so the word &quot;library&quot; is unambiguous between users and the new page.</p><h3 id="fail-closed-pipeline" tabindex="-1">Fail-closed pipeline <a class="header-anchor" href="#fail-closed-pipeline" aria-label="Permalink to &quot;Fail-closed pipeline&quot;">​</a></h3><p><code>scripts/build-link-provenance.ts</code> is the single source of truth for the manifest. It walks every <code>links[]</code> array and the <code>wiki</code> strings on small bodies, normalises the URL (strips <code>utm_*</code>, <code>fbclid</code>, AMP suffixes, mobile m-prefix), classifies the host against <code>source-logos.json</code>, infers the language from URL or marks for human review, then writes the manifest in deterministic order.</p><p><code>scripts/check-learn-links.ts</code> is the live-verification step. HEAD-probes every URL with retry, falls back to GET on 405, honours each host&#39;s <code>robots.txt</code>, records redirect chains, expired TLS, slow responses (&gt; 5 s). Writes <code>docs/provenance/last-link-check.md</code>.</p><p><code>scripts/validate-data.ts</code> enforces schema + integrity:</p><ul><li>Every <code>source_id</code> resolves in <code>source-logos.json</code>.</li><li>Every <code>language</code> is BCP-47 (or <code>*</code>).</li><li>No duplicate <code>(entity_id, url)</code> pairs.</li><li>No tracker query parameters survived normalisation.</li><li>Every <code>intro</code> / <code>core</code> link returned 2xx in the most recent <code>last-link-check.md</code> (when present); 4xx/5xx fail closed.</li><li><code>deep</code> 4xx/5xx warn but do not fail.</li></ul><p><code>npm run fetch</code> chains <code>fetch-assets &amp;&amp; build-image-provenance &amp;&amp; build-link-provenance &amp;&amp; check-learn-links &amp;&amp; validate-data</code> so a refetch re-derives every manifest and re-validates outbound links atomically.</p><p><code>npm run build</code> keeps <code>validate-data</code> only as the pre-hook (no live network in CI); the link-check report is the source of truth at build time.</p><h3 id="authoring-rule" tabindex="-1">Authoring rule <a class="header-anchor" href="#authoring-rule" aria-label="Permalink to &quot;Authoring rule&quot;">​</a></h3><p>When adding a new entity to <code>static/data/**</code> or a new link to an existing entity:</p><ol><li>The first <code>intro</code> link on a non-US entity is the operating agency portal.</li><li>Add the same link in the operator&#39;s native language when the operator publishes one.</li><li>Run <code>npm run build-link-provenance</code> to register the link in the manifest; if classification falls back to a <code>?</code> source, edit the row by hand to set a real <code>source_id</code>.</li><li>Run <code>npm run validate-data</code> and <code>npm run check-learn-links</code>; both must pass.</li><li>The link will appear on <code>/library</code> automatically.</li></ol><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Non-US missions get the editorial weight they deserve: their operator&#39;s own page is the first thing a user sees, in the operator&#39;s language when one exists.</li><li>Provenance is machine-checked: every outbound URL has a recorded source, language, and last-verified date.</li><li>Drift is fail-closed: a 4xx on an <code>intro</code> link breaks the build until the manifest is updated.</li><li>The public <code>/library</code> page is honest disclosure — every external link we send users to is enumerated, grouped, and dated.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>~25 entities need editorial enrichment in Milestone L-C.</li><li>The link-checker adds live network to <code>npm run fetch</code>. Build CI sticks to <code>validate-data</code> only; link-checking happens at refetch time, not on every PR.</li><li>Native-language pages may break first, since they are less stable than the English versions. The <code>replaced_with</code> audit trail is the answer.</li></ul><h3 id="out-of-scope-intentional-tracked-separately" tabindex="-1">Out of scope (intentional, tracked separately) <a class="header-anchor" href="#out-of-scope-intentional-tracked-separately" aria-label="Permalink to &quot;Out of scope (intentional, tracked separately)&quot;">​</a></h3><ul><li>Deep-link permission letters to non-Western agencies for content beyond what their public sites license — stays in <a href="https://github.com/chipi/orrery/issues/46" target="_blank" rel="noreferrer">#46</a>.</li><li>NASA-partnership-credit imagery enrichment — stays in <a href="https://github.com/chipi/orrery/issues/45" target="_blank" rel="noreferrer">#45</a>.</li><li>JSON-LD <code>sameAs</code> block on entity pages for SEO discoverability of source diversity — <code>docs/wip/learn-link-backlog.md</code>.</li><li>Translation of the editorial intro on <code>/library</code> beyond the existing 14 locales — follows the existing i18n process.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-046 — Agency-first build-time imagery sourcing.</li><li>ADR-047 — Provenance manifests + license stewardship.</li><li>RFC-015 — LEARN-link rollout (multi-milestone plan).</li><li>Epic <a href="https://github.com/chipi/orrery/issues/51" target="_blank" rel="noreferrer">#51</a> — LEARN-link stewardship rollout.</li></ul>`,49)])])}const k=i(t,[["render",n]]);export{u as __pageData,k as default};
